const query = $('input').item.json.query || '[imagen adjunta sin texto]';
const hasImage = !!$('input').item.json.image_base64;
const vars = $('Get_Variables').item.json;
const fecha = new Date().toLocaleDateString('es-MX', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
const imgNota = hasImage ? '\nNOTA: El usuario adjuntó una imagen; incluye búsqueda aunque sea charla casual.' : '';
const prompt = 'FECHA Y HORA ACTUAL: ' + fecha +
  '\n\nNUEVA CONSULTA: ' + query + imgNota +
  '\n\nClasifica esta consulta para búsqueda en la base de conocimientos.\n' +
  'REGLA CLAVE: Si la consulta tiene referencias temporales ("hoy", "esta semana", "este mes", "quién está de soporte/guardia/turno"), ' +
  'DEBES incluir la fecha actual (' + fecha + ') en las queries.\n\n' +
  'CLASIFICACIÓN DE QUERY:\n' +
  '- exact_id: códigos, IDs, tickets, errores específicos → semantic_weight=0.2, keyword_weight=0.8\n' +
  '- conceptual: cómo hacer algo, explicaciones → semantic_weight=0.7, keyword_weight=0.3\n' +
  '- mixed: conceptual + términos técnicos → semantic_weight=0.5, keyword_weight=0.5\n\n' +
  'Expande términos con sinónimos técnicos relevantes.\n\n' +
  'Responde SOLO con JSON válido sin markdown:\n' +
  '{"queries": ["query expandida"], "query_type": "conceptual|exact_id|mixed", "semantic_weight": 0.7, "keyword_weight": 0.3}';
return [{ json: { prompt } }];

// Respuesta cruda del agente (viene como texto)
const raw = $json.output || $json.text || '';
let plan = { queries: [], query_type: 'conceptual', semantic_weight: 0.7, keyword_weight: 0.3 };

try {
  let jsonStr = raw;
  if (typeof jsonStr === 'string') {
    jsonStr = jsonStr.replace(/```json\s*/gi, '').replace(/```\s*/gi, '').trim();
    const start = jsonStr.indexOf('{');
    const end = jsonStr.lastIndexOf('}');
    if (start !== -1 && end !== -1) {
      jsonStr = jsonStr.substring(start, end + 1);
    }
    plan = JSON.parse(jsonStr);
  } else if (typeof raw === 'object') {
    plan = raw;
  }
} catch (e) {
  // Fallback: usar la query original
  plan = {
    queries: [$('input').item.json.query || ''],
    query_type: 'conceptual',
    semantic_weight: 0.7,
    keyword_weight: 0.3
  };
}

const processInput = {
  query: $('input').item.json.query || '',
  hasImage: !!$('input').item.json.image_base64,
  imageData: $('input').item.json.image_base64 || null,
  imageMimeType: $('input').item.json.image_mime_type || 'image/jpeg',
  chat_id: $('input').item.json.chat_id
};

// Siempre buscar - asegurar que hay queries
const queries = (plan.queries && plan.queries.length > 0) ? plan.queries : [processInput.query || 'consulta'];
const querySearch = queries.slice(0, 2).join(' ');

return [{ json: {
  ...processInput,
  querySearch,
  queries,
  queryType: plan.query_type || 'conceptual',
  detectedManual: null,
  semanticWeight: plan.semantic_weight ?? 0.7,
  keywordWeight: plan.keyword_weight ?? 0.3
} }];

